import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';

@Injectable()
export class SanitizePasswordInterceptor implements NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest();
    if (request.body && request.body.password) {
      request.body = {
        ...request.body,
        password: '***REDACTED***',
      };
    }
    return next.handle();
  }
}
```

Puis l'appliquer globalement ou sur les routes concernées avec @UseInterceptors(SanitizePasswordInterceptor).

On utilise crypto.timingSafeEqual(a, b). Cette fonction nécessite que les deux buffers aient la même longueur. Exemple :
```typescript
import { timingSafeEqual } from 'crypto';

function safeCompare(a: string, b: string): boolean {
  if (a.length !== b.length) return false;
  return timingSafeEqual(Buffer.from(a), Buffer.from(b));
}
```
bcrypt l'utilise en interne, ce qui le rend sûr.

```typescript
import * as bcrypt from 'bcrypt';
import { randomBytes } from 'crypto';

async requestReset(email: string): Promise<void> {
  const user = await this.userService.findByEmail(email);
  if (!user) return; // Ne pas révéler si l'email existe (évite énumération)

  const rawToken = randomBytes(32).toString('hex');
  const hashedToken = await bcrypt.hash(rawToken, 10);
  const expiresAt = new Date();
  expiresAt.setHours(expiresAt.getHours() + 1);

  await this.resetTokenRepository.save({
    userId: user.id,
    tokenHash: hashedToken,
    expiresAt,
  });

  // Envoyer email avec lien contenant userId et rawToken
  await this.emailService.sendResetEmail(user.email, user.id, rawToken);
}
